import "strings"
func Solve(s string, f func(string) string) string { return strings.Map(func(r rune) rune { return r }, expand(s,f)) }
func expand(s string, f func(string) string) string { var b strings.Builder; for i:=0;i<len(s); { if s[i]!='$' {b.WriteByte(s[i]); i++; continue}; j:=i+1; for j<len(s)&&((s[j]>='a'&&s[j]<='z')||(s[j]>='A'&&s[j]<='Z')||(s[j]>='0'&&s[j]<='9')||s[j]=='_') {j++}; if j==i+1 {b.WriteByte(s[i]); i++; continue}; b.WriteString(f(s[i+1:j])); i=j }; return b.String() }

