import "sort"
type Person struct{Name string; Age int; Score int}
func Solve(xs []Person) []Person { out:=append([]Person{},xs...); sort.Slice(out,func(i,j int)bool{ a,b:=out[i],out[j]; if a.Age!=b.Age {return a.Age<b.Age}; if a.Score!=b.Score {return a.Score>b.Score}; return a.Name<b.Name }); return out }

